#include "pmsa003.h"
#include <HardwareSerial.h>
#include <Adafruit_PM25AQI.h>
static HardwareSerial pmSerial(1);
static Adafruit_PM25AQI aqi;
static uint16_t _pm10=0,_pm25=0,_pm100=0;
static unsigned long _last=0;
void pmsa003_setup(){pmSerial.begin(9600,SERIAL_8N1,16,17);if(!aqi.begin_UART(&pmSerial)){Serial.println("[pm] Fail!");return;}Serial.println("[pm] OK");}
void pmsa003_loop(){if(millis()-_last<2000)return;_last=millis();PM25_AQI_Data d;if(aqi.read(&d)){_pm10=d.pm10_standard;_pm25=d.pm25_standard;_pm100=d.pm100_standard;}}
uint16_t pmsa003_get_pm10(){return _pm10;}
uint16_t pmsa003_get_pm25(){return _pm25;}
uint16_t pmsa003_get_pm100(){return _pm100;}
